form:Form.form:Scripts:
		function onload()
{
	if(Ctrl("main").GetMode() == "NEW")
	{
		for (var i=0; i<Ctrl('MAIN_GRID').TotalRowsCount(); i++)              
			Ctrl("MAIN_GRID").SetCellXValue('f_monto', i, datetime2str(Now()));		
	}
	else
	{  
	   //si no hay registros en la grilla deshabilito botón de agregar montos ya que no se puede hacer nada.
	   if (Ctrl('MAIN_GRID').TotalRowsCount()==0)
	     CtrlEnabled('ADD', false);
	} 

  //seteo valor al control tipo de monto usando el control oculto
	Ctrl('oi_tipo_monto').SetXValue(Ctrl('hid_oi_tipo_monto').GetXValue());

}

function SetMonto()
{
	var MyControlMontoFact = Ctrl('MAIN_GRID').GetCellSelectedControl('n_monto_fact');

	if(Ctrl('MAIN_GRID').GetCellSelectedControl('l_facturable').GetXValue() == "1")
	{
		var MyControlMonto = Ctrl('MAIN_GRID').GetCellSelectedControl('n_monto');
		MyControlMontoFact.SetTypedValue(MyControlMonto.TypedValue());
	}
	else
		MyControlMontoFact.SetTypedValue("");
}

function SetValores()
{              
	var MyControlMontoPrev = Ctrl('MAIN_GRID').GetCellSelectedControl('n_monto_prev');
	var MyControlPrev = Ctrl('MAIN_GRID').GetCellSelectedControl('n_prevision');

	if(MyControlPrev.GetXValue() != "")
		SetValorMonto();
	else
		if(MyControlMontoPrev.GetXValue() != "")
			SetValorPrev();
}

function SetValorMonto()
{ 
	var MyControlMontoPrev = Ctrl('MAIN_GRID').GetCellSelectedControl('n_monto_prev');
	var MyControlPrev = Ctrl('MAIN_GRID').GetCellSelectedControl('n_prevision');
	var MyControlMontoPrevCosto = Ctrl('MAIN_GRID').GetCellSelectedControl('n_monto_prev_c');
	var MyControlPrevCosto = Ctrl('MAIN_GRID').GetCellSelectedControl('n_prevision_c');
	var MyControlMonto = Ctrl('MAIN_GRID').GetCellSelectedControl('n_monto');

	if(MyControlPrev.GetXValue() != "")
	{   
		var calculo;              
		var prevision = MyControlPrev.TypedValue() / 100.00;
		calculo = MyControlMonto.TypedValue() * prevision;

		MyControlMontoPrev.SetTypedValue(calculo);
		MyControlMontoPrev.SetEnabled(false); 

		var MontoPrevCosto = calculo * MyControlPrevCosto.TypedValue() / 100.00;
		MyControlMontoPrevCosto.SetTypedValue(MontoPrevCosto);
		MyControlMontoPrevCosto.SetEnabled(false); 
	}
	else
	{                                   
		MyControlMontoPrev.SetXValue("");
		MyControlMontoPrev.SetEnabled(true);             

		MyControlMontoPrevCosto.SetTypedValue("");
		MyControlMontoPrevCosto.SetEnabled(false); 
	}	
}


function SetValorPrev()
{ 
	var MyControlMontoPrev = Ctrl('MAIN_GRID').GetCellSelectedControl('n_monto_prev');
	var MyControlPrev = Ctrl('MAIN_GRID').GetCellSelectedControl('n_prevision');

	var MyControlMontoPrevCosto = Ctrl('MAIN_GRID').GetCellSelectedControl('n_monto_prev_c');
	var MyControlPrevCosto = Ctrl('MAIN_GRID').GetCellSelectedControl('n_prevision_c');

	var MyControlMonto = Ctrl('MAIN_GRID').GetCellSelectedControl('n_monto');

	if(MyControlMontoPrev.GetXValue() != "")
	{   
		var calculo;              

		calculo = MyControlMontoPrev.TypedValue() * 100.00 / MyControlMonto.TypedValue();

		MyControlPrev.SetTypedValue(calculo);
		MyControlPrev.SetEnabled(false);

		var MontoPrevCosto = calculo * MyControlPrevCosto.TypedValue() / 100.00;
		MyControlMontoPrevCosto.SetTypedValue(MontoPrevCosto);
		MyControlMontoPrevCosto.SetEnabled(false); 
	}
	else
	{                                   
		MyControlPrev.SetXValue("");
		MyControlPrev.SetEnabled(true);

		MyControlMontoPrevCosto.SetTypedValue("");
		MyControlMontoPrevCosto.SetEnabled(false); 
	}
}

function validaTipoMonto()
{ 
  //si hay registros en la grilla sigue con la validación
  if (Ctrl('MAIN_GRID').TotalRowsCount()>0)
  { 
    //si el control tipo de monto es vacío
    if (Ctrl('oi_tipo_monto').GetXValue()=="")
    {
      alert('El valor es requerido');
      CtrlFocus('oi_tipo_monto'); 
      return false;
    }

    var xmlParam = new NomadXML("PARAMS");

  	xmlParam.SetAttr("oi_tipo_carpeta",Ctrl('hid_tipo_carpeta').GetXValue());       
	  np = new NomadProxy("", ut);
  	nSQL = np.SQLService();

    xmlParam.SetAttr("oi_tipo_monto",Ctrl('oi_tipo_monto').GetXValue());   

	  var cant = nSQL.GetOBJ(Ctrl("main").getResource("QRY_TIENE_TIPO_CARPETA"), xmlParam.ToString());        

	  if(cant.cant==0 && Ctrl("main").GetMode() != "NEW")
	  {
	    alert('El tipo de monto actual no corresponde al tipo de carpeta. Debe agregar nuevos montos para poder cambiar el tipo de monto');
	    return false;
  	}


  	if(cant.cant==0)
	  {
	    alert('El tipo de monto actual no corresponde al tipo de carpeta.');
	    return false;
  	}  

    //seteo el nuevo valor tipo de monto en el control oculto  (si pasa validación)
    Ctrl('hid_oi_tipo_monto').SetXValue(Ctrl('oi_tipo_monto').GetXValue());
  }

  return true; 
}
